import { useState, useEffect } from "react";
import { useLocation } from "react-router-dom";
import { ChevronUp } from "lucide-react";
import { cn } from "@/lib/utils";

const ScrollToTopButton = () => {
  const [isVisible, setIsVisible] = useState(false);
  const location = useLocation();

  // Hide on community page
  const isHiddenRoute = location.pathname === "/community" || location.pathname.startsWith("/community/");

  useEffect(() => {
    const toggleVisibility = () => {
      // Show button when page is scrolled down 300px
      if (window.scrollY > 300 && !isHiddenRoute) {
        setIsVisible(true);
      } else {
        setIsVisible(false);
      }
    };

    window.addEventListener("scroll", toggleVisibility);
    return () => window.removeEventListener("scroll", toggleVisibility);
  }, [isHiddenRoute]);

  const scrollToTop = () => {
    window.scrollTo({
      top: 0,
      behavior: "smooth",
    });
  };

  return (
    <button
      onClick={scrollToTop}
      className={cn(
        "fixed bottom-20 right-3 z-50 w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-white dark:bg-background shadow-lg flex items-center justify-center transition-all duration-300 hover:scale-110 active:scale-95 border border-border/50",
        isVisible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-4 pointer-events-none"
      )}
      aria-label="Scroll to top"
    >
      <ChevronUp className="w-4 h-4 sm:w-5 sm:h-5 text-primary" />
    </button>
  );
};

export default ScrollToTopButton;
