import { Component, ErrorInfo, ReactNode } from 'react';
import { supabase } from '@/integrations/supabase/client';

interface Props {
  children: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
  copied?: boolean;
}

class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false,
    error: null,
    errorInfo: null,
    copied: false,
  };

  public static getDerivedStateFromError(error: Error): Partial<State> {
    return { hasError: true, error, errorInfo: null };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('App Error:', error, errorInfo);
    this.setState({ errorInfo });
    
    // Remove loader if it exists
    const loader = document.getElementById('initial-loader');
    if (loader && loader.parentNode) {
      loader.parentNode.removeChild(loader);
    }
    document.body.classList.remove('app-loading');

    // Auto-report error to database
    this.reportError(error, errorInfo);
  }

  private async reportError(error: Error, errorInfo: ErrorInfo) {
    try {
      await supabase.from('error_reports').insert({
        error_message: error.toString(),
        error_stack: error.stack?.slice(0, 2000) || null,
        component_stack: errorInfo.componentStack?.slice(0, 2000) || null,
        url: window.location.href,
        user_agent: navigator.userAgent,
      });
      console.log('[ErrorBoundary] Error reported to database');
    } catch (e) {
      console.warn('[ErrorBoundary] Failed to report error:', e);
    }
  }

  private getErrorSummary(): string {
    const error = this.state.error;
    const info = this.state.errorInfo;
    const ua = typeof navigator !== 'undefined' ? navigator.userAgent : 'unknown';
    const url = typeof window !== 'undefined' ? window.location.href : 'unknown';
    return [
      `Error: ${error?.toString() || 'unknown'}`,
      `URL: ${url}`,
      `UA: ${ua}`,
      `Stack: ${error?.stack?.slice(0, 500) || 'none'}`,
      `Component: ${info?.componentStack?.slice(0, 300) || 'none'}`,
    ].join('\n');
  }

  private handleCopyError = () => {
    const summary = this.getErrorSummary();
    if (navigator.clipboard) {
      navigator.clipboard.writeText(summary).then(() => {
        this.setState({ copied: true } as any);
        setTimeout(() => this.setState({ copied: false } as any), 2000);
      }).catch(() => {
        // Fallback: select text
        prompt('请复制以下错误信息：', summary);
      });
    } else {
      prompt('请复制以下错误信息：', summary);
    }
  };

  public render() {
    if (this.state.hasError) {
      const copied = (this.state as any).copied;
      return (
        <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
          <div className="max-w-md w-full bg-white rounded-lg shadow-lg p-6 text-center">
            <div className="text-6xl mb-4">😕</div>
            <h1 className="text-xl font-bold text-gray-900 mb-2">
              页面加载出错
            </h1>
            <p className="text-gray-600 mb-4">
              请尝试刷新页面或稍后再试
            </p>
            <div className="flex gap-3 justify-center">
              <button
                onClick={() => window.location.reload()}
                className="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700 transition-colors"
              >
                刷新页面
              </button>
              <button
                onClick={this.handleCopyError}
                className="bg-gray-200 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-300 transition-colors text-sm"
              >
                {copied ? '✓ 已复制' : '复制错误信息'}
              </button>
            </div>
            {this.state.error && (
              <details className="mt-4 text-left text-sm text-red-600 bg-red-50 p-3 rounded">
                <summary className="cursor-pointer font-medium">错误详情（点击展开）</summary>
                <pre className="mt-2 whitespace-pre-wrap overflow-auto max-h-40 text-xs">
                  {this.state.error.toString()}
                  {this.state.errorInfo?.componentStack}
                </pre>
              </details>
            )}
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;
