/**
 * ⚠️ 应用入口 / APPLICATION ENTRY POINT ⚠️
 * 
 * CRITICAL: auth-fetch-interceptor MUST be the first import!
 * It wraps window.fetch BEFORE the Supabase SDK captures a reference to it.
 * ES modules hoist imports, so this is the ONLY way to guarantee execution order.
 */

// ===== MUST BE FIRST: Install fetch interceptor before Supabase SDK loads =====
import "./auth-fetch-interceptor";

import { createRoot } from "react-dom/client";
import App from "./App.tsx";
import "./index.css";
import "./i18n/config";
import { setupFCMTokenListener } from "./lib/fcmBridge";

// Set up passive FCM token listener early (before login) - wrapped for safety
try {
  setupFCMTokenListener();
} catch (e) {
  try {
    console.warn("[Main] FCM setup failed (non-critical):", e);
  } catch {
    // silent
  }
}

const root = document.getElementById("root");
if (root) {
  try {
    createRoot(root).render(<App />);
  } catch (e) {
    // Last resort fallback - show something instead of white screen
    try {
      console.error("[Main] React render failed:", e);
      root.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100vh;font-family:sans-serif;text-align:center;padding:20px"><div><p style="font-size:18px;margin-bottom:12px">页面加载出错</p><button onclick="location.reload()" style="padding:8px 24px;background:#3b82f6;color:white;border:none;border-radius:8px;font-size:16px">刷新页面</button></div></div>';
    } catch {
      // truly nothing we can do
    }
  }
}
