/**
 * ⚠️ 应用入口文件 / APPLICATION ENTRY FILE ⚠️
 * 
 * 优化注意事项 / Optimization Notes:
 * 
 * 1. Provider 嵌套顺序 / Provider Nesting Order:
 *    QueryClientProvider → ThemeProvider → TooltipProvider → BrowserRouter → AuthProvider
 *    - AuthProvider 必须在 BrowserRouter 内部（因为使用 useNavigate）
 *    - AuthProvider must be inside BrowserRouter (uses useNavigate)
 *    - 修改嵌套顺序可能导致 hook 调用错误
 *    - Changing nesting order may cause hook call errors
 * 
 * 2. 懒加载安全 / Lazy Loading Safety:
 *    - React.lazy() 加载的组件不会触发循环依赖问题
 *    - React.lazy() loaded components won't trigger circular dependency issues
 *    - 新增页面组件时优先使用懒加载
 *    - Use lazy loading when adding new page components
 * 
 * 3. 避免直接导入 / Avoid Direct Imports:
 *    - 不要在此文件直接导入使用 useAuth 的组件（除非懒加载）
 *    - Don't directly import components using useAuth here (unless lazy loaded)
 */
import { Suspense, useEffect, useRef } from "react";
import { lazyRetry } from "@/lib/lazyRetry";
import ErrorBoundary from "./components/ErrorBoundary";
import { useIOSSwipeBack } from "@/hooks/useIOSSwipeBack";
import { incrementNavDepth, resetNavDepth } from "@/hooks/useSmartBack";
import { Toaster } from "@/components/ui/toaster";
import { Toaster as Sonner } from "@/components/ui/sonner";
import { TooltipProvider } from "@/components/ui/tooltip";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { BrowserRouter, Routes, Route, useLocation } from "react-router-dom";
import { ThemeProvider } from "next-themes";
import { AuthProvider } from "./contexts/AuthContext";
import { VideoTaskProvider } from "./contexts/VideoTaskContext";
import Navigation from "./components/layout/Navigation";
import VideoTaskFloatingWidget from "./components/VideoTaskFloatingWidget";
import Footer from "./components/layout/Footer";
import { ScrollToTop } from "./components/ScrollToTop";
import ScrollToTopButton from "./components/ScrollToTopButton";
import { DynamicFavicon } from "./components/DynamicFavicon";
import DynamicSEO from "./components/DynamicSEO";
// Auth is lazy-loaded but preloaded from pages that link to it (e.g. JoinUs)
// Lazy load presence trackers to avoid useAuth issues during module load
const UserPresenceTracker = lazyRetry(() => import("./components/UserPresenceTracker"));
const VisitorPresenceTracker = lazyRetry(() => import("./components/VisitorPresenceTracker"));

import { isInWebView } from "@/lib/externalLinks";

// Page skeleton for lazy loading fallback
import { PageSkeleton, HomeSkeleton } from "./components/skeletons";
// Lazy loaded pages - reduces initial bundle size significantly
const AskXiaoxiong = lazyRetry(() => import("./pages/AskXiaoxiong"));
const Home = lazyRetry(() => import("./pages/Home"));
const Restaurants = lazyRetry(() => import("./pages/Restaurants"));
const RestaurantDetail = lazyRetry(() => import("./pages/RestaurantDetail"));
const Map = lazyRetry(() => import("./pages/Map"));
const Activities = lazyRetry(() => import("./pages/Activities"));
const ActivityDetail = lazyRetry(() => import("./pages/ActivityDetail"));
const Auth = lazyRetry(() => import("./pages/Auth"));
const Profile = lazyRetry(() => import("./pages/Profile"));
const JoinUs = lazyRetry(() => import("./pages/JoinUs"));
const PrivacyPolicy = lazyRetry(() => import("./pages/PrivacyPolicy"));
const TermsOfService = lazyRetry(() => import("./pages/TermsOfService"));
const AboutUs = lazyRetry(() => import("./pages/AboutUs"));
const Contact = lazyRetry(() => import("./pages/Contact"));
const NotFound = lazyRetry(() => import("./pages/NotFound"));
const Dashboard = lazyRetry(() => import("./pages/Dashboard"));
const RestaurantRedirect = lazyRetry(() => import("./pages/RestaurantRedirect"));
const MerchantActivityRequestForm = lazyRetry(() => import("./pages/MerchantActivityRequestForm"));
const DeleteAccountRequest = lazyRetry(() => import("./pages/DeleteAccountRequest"));

// Admin pages - lazy loaded as they're rarely accessed initially
const AdminLayout = lazyRetry(() => import("./components/admin/AdminLayout"));
const AdminDashboard = lazyRetry(() => import("./pages/admin/AdminDashboard"));
const AdminUsers = lazyRetry(() => import("./pages/admin/AdminUsers"));
const AdminRestaurants = lazyRetry(() => import("./pages/admin/AdminRestaurants"));
const AdminActivities = lazyRetry(() => import("./pages/admin/AdminActivities"));
const AdminCoupons = lazyRetry(() => import("./pages/admin/AdminCoupons"));
const AdminCouponDetail = lazyRetry(() => import("./pages/admin/AdminCouponDetail"));
const AdminReports = lazyRetry(() => import("./pages/admin/AdminReports"));
const AdminJoinRequests = lazyRetry(() => import("./pages/admin/AdminJoinRequests"));
const AdminStorePublications = lazyRetry(() => import("./pages/admin/AdminStorePublications"));
const AdminHomepageTemplates = lazyRetry(() => import("./pages/admin/AdminHomepageTemplates"));
const AdminLogs = lazyRetry(() => import("./pages/admin/AdminLogs"));
const AdminActivityRequests = lazyRetry(() => import("./pages/admin/AdminActivityRequests"));
const AdminRatings = lazyRetry(() => import("./pages/admin/AdminRatings"));
const AdminSensitiveWords = lazyRetry(() => import("./pages/admin/AdminSensitiveWords"));
const AdminApiDocs = lazyRetry(() => import("./pages/admin/AdminApiDocs"));
const AdminSiteSettings = lazyRetry(() => import("./pages/admin/AdminSiteSettings"));
const AdminAnalytics = lazyRetry(() => import("./pages/admin/AdminAnalytics"));
const AdminActivityStats = lazyRetry(() => import("./pages/admin/AdminActivityStats"));
const AdminActivityStatsList = lazyRetry(() => import("./pages/admin/AdminActivityStatsList"));
const AdminRestaurantStats = lazyRetry(() => import("./pages/admin/AdminRestaurantStats"));
const AdminRestaurantStatsList = lazyRetry(() => import("./pages/admin/AdminRestaurantStatsList"));
const AdminOrderStats = lazyRetry(() => import("./pages/admin/AdminOrderStats"));
const AdminNotifications = lazyRetry(() => import("./pages/admin/AdminNotifications"));
const AdminEmails = lazyRetry(() => import("./pages/admin/AdminEmails"));
const AdminUserManual = lazyRetry(() => import("./pages/admin/AdminUserManual"));
const AdminUserSecurity = lazyRetry(() => import("./pages/admin/AdminUserSecurity"));
const AdminBannedUsers = lazyRetry(() => import("./pages/admin/AdminBannedUsers"));
const AdminMutedUsers = lazyRetry(() => import("./pages/admin/AdminMutedUsers"));
const AdminFeedback = lazyRetry(() => import("./pages/admin/AdminFeedback"));
const AdminComments = lazyRetry(() => import("./pages/admin/AdminComments"));
const AdminPoints = lazyRetry(() => import("./pages/admin/AdminPoints"));
const AdminShopItems = lazyRetry(() => import("./pages/admin/AdminShopItems"));
const AdminPointsSettings = lazyRetry(() => import("./pages/admin/AdminPointsSettings"));
const AdminNavigationSettings = lazyRetry(() => import("./pages/admin/AdminNavigationSettings"));
const AdminAISettings = lazyRetry(() => import("./pages/admin/AdminAISettings"));
const AdminAIConfigList = lazyRetry(() => import("./pages/admin/AdminAIConfigList"));
const AdminAIConfigDetail = lazyRetry(() => import("./pages/admin/AdminAIConfigDetail"));
const AdminLovableAIConfig = lazyRetry(() => import("./pages/admin/AdminLovableAIConfig"));
const AdminCommunityPosts = lazyRetry(() => import("./pages/admin/AdminCommunityPosts"));
const AdminCommunityModeration = lazyRetry(() => import("./pages/admin/AdminCommunityModeration"));
const AdminEmailVerification = lazyRetry(() => import("./pages/admin/AdminEmailVerification"));
const AdminInvitationCodes = lazyRetry(() => import("./pages/admin/AdminInvitationCodes"));
const AdminBrands = lazyRetry(() => import("./pages/admin/AdminBrands"));
const AdminAds = lazyRetry(() => import("./pages/admin/AdminAds"));
const AdminAIRecipes = lazyRetry(() => import("./pages/admin/AdminAIRecipes"));
const AdminVideoUsage = lazyRetry(() => import("./pages/admin/AdminVideoUsage"));
const AdminWatermarkTool = lazyRetry(() => import("./pages/admin/AdminWatermarkTool"));


// Community pages - lazy loaded
const Community = lazyRetry(() => import("./pages/Community"));
const PostDetail = lazyRetry(() => import("./pages/PostDetail"));
const AIRecipeSelect = lazyRetry(() => import("./pages/AIRecipeSelect"));
const AIRecipe = lazyRetry(() => import("./pages/AIRecipe"));
const WhatToEat = lazyRetry(() => import("./pages/WhatToEat"));
const SavedRecipeDetail = lazyRetry(() => import("./pages/SavedRecipeDetail"));

// User pages - lazy loaded
const Shop = lazyRetry(() => import("./pages/Shop"));
const Membership = lazyRetry(() => import("./pages/Membership"));
const PublicProfile = lazyRetry(() => import("./pages/PublicProfile"));

// Merchant pages - lazy loaded
const MerchantLayout = lazyRetry(() => import("./components/merchant/MerchantLayout"));
const MerchantDashboard = lazyRetry(() => import("./pages/merchant/MerchantDashboard"));
const MerchantActivityRequests = lazyRetry(() => import("./pages/merchant/MerchantActivityRequests"));
const MerchantCouponQuery = lazyRetry(() => import("./pages/merchant/MerchantCouponQuery"));

// Optimized QueryClient with better caching to reduce unnecessary refetches
const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 5 * 60 * 1000, // 5 minutes - data won't refetch within this time
      gcTime: 30 * 60 * 1000, // 30 minutes - keep cached data in memory
      refetchOnWindowFocus: false, // Don't refetch when window regains focus
      retry: 1, // Only retry once on failure
    },
  },
});

// Component to remove initial loader once app is ready
const LoaderCleanup = () => {
  useEffect(() => {
    // Remove the initial HTML loader once React has mounted
    const loader = document.getElementById('initial-loader');
    if (loader) {
      loader.classList.add('fade-out');
      setTimeout(() => {
        if (loader.parentNode) {
          loader.parentNode.removeChild(loader);
        }
      }, 300);
    }
    document.body.classList.remove('app-loading');
  }, []);
  return null;
};

// Main app content with conditional padding
const MobileBottomNav = lazyRetry(() => import("./components/layout/MobileBottomNav"));
const RouteGuard = lazyRetry(() => import("./components/RouteGuard"));

const AppContent = () => {
  const location = useLocation();
  const isHomePage = location.pathname === '/';
  const isInstagramContact = location.pathname === '/instagramContact';
  const isChatPage = location.pathname === '/ai-recipe/what-to-eat';
  const isAuthPage = location.pathname === '/auth';
  // Enable iOS edge swipe back gesture for iOS WebView/Capacitor apps
  useIOSSwipeBack();

  // Track internal navigation depth for smart back button
  const isFirstRender = useRef(true);
  useEffect(() => {
    if (isFirstRender.current) {
      isFirstRender.current = false;
      resetNavDepth();
    } else {
      incrementNavDepth();
    }
  }, [location.pathname]);
  
  return (
    <>
      {!isInstagramContact && <Navigation />}
      {!isInstagramContact && <VideoTaskFloatingWidget />}
      <div className={`${isHomePage || isInstagramContact ? '' : 'pt-14 sm:pt-16'} min-h-screen flex flex-col ${isInstagramContact ? '' : 'pb-16 md:pb-0'}`}>
        <div className="flex-1">
          <Suspense fallback={isAuthPage ? null : <PageSkeleton showHeader={false} showFilters={false} />}>
            <RouteGuard>
              <Routes>
                <Route path="/" element={
                  <Suspense fallback={<HomeSkeleton />}>
                    <Home />
                  </Suspense>
                } />
                <Route path="/restaurants" element={<Restaurants />} />
                <Route path="/restaurant/:id" element={<RestaurantDetail />} />
                <Route path="/r/:keyId" element={<RestaurantRedirect />} />
                <Route path="/map" element={<Map />} />
                <Route path="/activities" element={<Activities />} />
                <Route path="/activity/:id" element={<ActivityDetail />} />
                <Route path="/community" element={<Community />} />
                <Route path="/community/posts" element={<Community />} />
                <Route path="/community/recipes" element={<Community />} />
                <Route path="/community/post/:id" element={<PostDetail />} />
                <Route path="/ai-recipe" element={<AIRecipeSelect />} />
                <Route path="/ai-recipe/how-to-cook" element={<AIRecipe />} />
                <Route path="/ai-recipe/what-to-eat" element={<WhatToEat />} />
                <Route path="/saved-recipe/:id" element={<SavedRecipeDetail />} />
                <Route path="/auth" element={<Auth />} />
                <Route path="/profile" element={<Profile />} />
                <Route path="/user/:userId" element={<PublicProfile />} />
                <Route path="/shop" element={<Shop />} />
                <Route path="/membership" element={<Membership />} />
                <Route path="/join-us" element={<JoinUs />} />
                <Route path="/privacy-policy" element={<PrivacyPolicy />} />
                <Route path="/terms-of-service" element={<TermsOfService />} />
                <Route path="/about-us" element={<AboutUs />} />
                <Route path="/delete-account" element={<DeleteAccountRequest />} />
                <Route path="/instagramContact" element={<Contact />} />
                <Route path="/dashboard" element={<Dashboard />} />
                <Route path="/ask-xiaoxiong" element={<AskXiaoxiong />} />
                <Route path="/admin" element={<AdminLayout />}>
                  <Route index element={<AdminDashboard />} />
                  <Route path="users" element={<AdminUsers />} />
                  <Route path="restaurants" element={<AdminRestaurants />} />
                  <Route path="activities" element={<AdminActivities />} />
                  <Route path="coupons" element={<AdminCoupons />} />
                  <Route path="coupons/:id" element={<AdminCouponDetail />} />
                  <Route path="coupon-query" element={<MerchantCouponQuery />} />
                  <Route path="activity-requests" element={<AdminActivityRequests />} />
                  <Route path="logs" element={<AdminLogs />} />
                  <Route path="homepage-templates" element={<AdminHomepageTemplates />} />
                  <Route path="join-requests" element={<AdminJoinRequests />} />
                  <Route path="store-publications" element={<AdminStorePublications />} />
                  <Route path="reports" element={<AdminReports />} />
                  <Route path="ratings" element={<AdminRatings />} />
                  <Route path="sensitive-words" element={<AdminSensitiveWords />} />
                  <Route path="api-docs" element={<AdminApiDocs />} />
                  <Route path="site-settings" element={<AdminSiteSettings />} />
                  <Route path="navigation-settings" element={<AdminNavigationSettings />} />
                  <Route path="analytics" element={<AdminAnalytics />} />
                  <Route path="activity-stats" element={<AdminActivityStatsList />} />
                  <Route path="activity-stats/:id" element={<AdminActivityStats />} />
                  <Route path="restaurant-stats" element={<AdminRestaurantStatsList />} />
                  <Route path="restaurant-stats/:id" element={<AdminRestaurantStats />} />
                  <Route path="order-stats" element={<AdminOrderStats />} />
                  <Route path="notifications" element={<AdminNotifications />} />
                  <Route path="emails" element={<AdminEmails />} />
                  <Route path="user-manual" element={<AdminUserManual />} />
                  <Route path="user-security" element={<AdminUserSecurity />} />
                  <Route path="banned-users" element={<AdminBannedUsers />} />
                  <Route path="muted-users" element={<AdminMutedUsers />} />
                  <Route path="feedback" element={<AdminFeedback />} />
                  <Route path="comments" element={<AdminComments />} />
                  <Route path="points" element={<AdminPoints />} />
                  <Route path="shop-items" element={<AdminShopItems />} />
                  <Route path="points-settings" element={<AdminPointsSettings />} />
                  <Route path="ai-settings" element={<AdminAISettings />} />
                  <Route path="ai-config" element={<AdminAIConfigList />} />
                  <Route path="ai-config/lovable-ai" element={<AdminLovableAIConfig />} />
                  <Route path="ai-config/:provider" element={<AdminAIConfigDetail />} />
                  <Route path="community-posts" element={<AdminCommunityPosts />} />
                  <Route path="community-moderation" element={<AdminCommunityModeration />} />
                  <Route path="email-verification" element={<AdminEmailVerification />} />
                  <Route path="invitation-codes" element={<AdminInvitationCodes />} />
                  <Route path="brands" element={<AdminBrands />} />
                  <Route path="ads" element={<AdminAds />} />
                  <Route path="ai-recipes" element={<AdminAIRecipes />} />
                  <Route path="video-usage" element={<AdminVideoUsage />} />
                  <Route path="watermark-tool" element={<AdminWatermarkTool />} />
                  
                </Route>
                <Route path="/merchant-dashboard" element={<MerchantLayout />}>
                  <Route index element={<MerchantDashboard />} />
                  <Route path="activity-requests" element={<MerchantActivityRequests />} />
                  <Route path="coupon-query" element={<MerchantCouponQuery />} />
                  <Route path="user-manual" element={<AdminUserManual />} />
                  <Route path="membership" element={<Membership />} />
                </Route>
                <Route path="/merchant/activity-request-form" element={<MerchantActivityRequestForm />} />
                <Route path="*" element={<NotFound />} />
              </Routes>
            </RouteGuard>
          </Suspense>
        </div>
        
        {!isInstagramContact && !isChatPage && <Footer />}
      </div>
      <Suspense fallback={null}>
        <MobileBottomNav />
      </Suspense>
    </>
  );
};

const App = () => (
  <ErrorBoundary>
    <QueryClientProvider client={queryClient}>
      <ThemeProvider attribute="class" defaultTheme="system" enableSystem>
        <TooltipProvider>
          <Toaster />
          <Sonner />
          <BrowserRouter future={{ v7_startTransition: true }}>
            <AuthProvider>
              <VideoTaskProvider>
              <LoaderCleanup />
              <ScrollToTop />
              <DynamicFavicon />
              <DynamicSEO />
              <Suspense fallback={null}>
                <UserPresenceTracker />
                <VisitorPresenceTracker />
              </Suspense>
              <AppContent />
              <ScrollToTopButton />
              </VideoTaskProvider>
            </AuthProvider>
          </BrowserRouter>
        </TooltipProvider>
      </ThemeProvider>
    </QueryClientProvider>
  </ErrorBoundary>
);

export default App;
