import { useTranslation } from "react-i18next";
import { Button } from "@/components/ui/button";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Globe } from "lucide-react";
import { useUpdateLanguagePreference } from "@/hooks/useProfile";
import { useAuth } from "@/contexts/AuthContext";
const languages = [
  { code: "de", name: "Deutsch", flag: "🇩🇪" },
  { code: "en", name: "English", flag: "🇬🇧" },
  { code: "es", name: "Español", flag: "🇪🇸" },
  { code: "fr", name: "Français", flag: "🇫🇷" },
  { code: "it", name: "Italiano", flag: "🇮🇹" },
  { code: "pt", name: "Português", flag: "🇵🇹" },
  { code: "ar", name: "العربية", flag: "🇸🇦" },
  { code: "ru", name: "Русский", flag: "🇷🇺" },
  { code: "ja", name: "日本語", flag: "🇯🇵" },
  { code: "ko", name: "한국어", flag: "🇰🇷" },
  { code: "zh", name: "中文", flag: "🇨🇳" },
];

const DEFAULT_LANGUAGE = languages.find(l => l.code === "en")!;
export const LanguageSwitcher = ({ className }: { className?: string }) => {
  const {
    i18n
  } = useTranslation();
  const {
    user
  } = useAuth();
  const updateLanguagePreference = useUpdateLanguagePreference();
  const resolvedLang = i18n.language?.split('-')[0] || 'en';
  const currentLanguage = languages.find(lang => lang.code === resolvedLang) || DEFAULT_LANGUAGE;
  const changeLanguage = async (langCode: string) => {
    // Save to localStorage first for persistence
    localStorage.setItem("i18nextLng", langCode);
    // Await the language change to ensure it completes
    await i18n.changeLanguage(langCode);
    // Update user's language preference in database if logged in
    if (user) {
      updateLanguagePreference.mutate(langCode);
    }
  };
  return <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon" title="Change Language" className={`border-0 ${className || "text-foreground hover:bg-accent hover:text-accent-foreground"}`}>
          <Globe className="w-5 h-5" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        {languages.map(lang => <DropdownMenuItem key={lang.code} onClick={() => changeLanguage(lang.code)} className={`cursor-pointer ${currentLanguage.code === lang.code ? "bg-accent" : ""}`}>
            <span className="mr-2">{lang.flag}</span>
            <span>{lang.name}</span>
          </DropdownMenuItem>)}
      </DropdownMenuContent>
    </DropdownMenu>;
};