import { useState, useEffect, useRef, useCallback, lazy, Suspense } from "react";
import { useTranslation } from "react-i18next";
import { useVideoTasks, BGVideoTask } from "@/contexts/VideoTaskContext";
import { Video, Loader2, CheckCircle2, XCircle, X, ChevronDown, ChevronUp } from "lucide-react";
import { cn } from "@/lib/utils";

const SavedRecipeDetailDialog = lazy(() => import("@/components/ai-recipe/SavedRecipeDetailDialog"));

const AUTO_HIDE_DELAY = 10000;
const FADE_START = 7000;

/** Track whether user has opened the expanded panel at least once after tasks completed */

const VideoTaskFloatingWidget = () => {
  const { t } = useTranslation();
  const { tasks, markViewed, removeTask, activeCount, showGuideAnimation, clearGuideAnimation } = useVideoTasks();
  const [expanded, setExpanded] = useState(false);
  const [opacity, setOpacity] = useState(1);
  const hideTimerRef = useRef<number | null>(null);
  const fadeIntervalRef = useRef<number | null>(null);
  const startTimeRef = useRef<number>(0);
  /** Has the user opened the panel at least once since tasks completed? */
  const hasViewedAfterDone = useRef(false);

  // Recipe detail dialog state
  const [selectedTask, setSelectedTask] = useState<BGVideoTask | null>(null);

  const visibleTasks = tasks.filter(t =>
    t.status === "creating" || t.status === "processing" ||
    (t.status === "succeeded" && !t.viewed) ||
    (t.status === "failed" && !t.viewed)
  );
  const hasVisible = visibleTasks.length > 0;
  const processingCount = tasks.filter(t => t.status === "creating" || t.status === "processing").length;
  const completedUnviewed = tasks.filter(t => (t.status === "succeeded" || t.status === "failed") && !t.viewed).length;
  const allDone = hasVisible && processingCount === 0 && completedUnviewed > 0;

  const startAutoHide = useCallback(() => {
    if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    if (fadeIntervalRef.current) clearInterval(fadeIntervalRef.current);
    setOpacity(1);
    startTimeRef.current = Date.now();
    fadeIntervalRef.current = window.setInterval(() => {
      const elapsed = Date.now() - startTimeRef.current;
      if (elapsed >= FADE_START) {
        const newOpacity = Math.max(0, 1 - (elapsed - FADE_START) / (AUTO_HIDE_DELAY - FADE_START));
        setOpacity(newOpacity);
      }
    }, 100);
    hideTimerRef.current = window.setTimeout(() => {
      if (fadeIntervalRef.current) clearInterval(fadeIntervalRef.current);
      visibleTasks.forEach(t => {
        if (t.status === "succeeded" || t.status === "failed") markViewed(t.id);
      });
      setExpanded(false);
    }, AUTO_HIDE_DELAY);
  }, [visibleTasks, markViewed]);

  const stopAutoHide = useCallback(() => {
    if (hideTimerRef.current) { clearTimeout(hideTimerRef.current); hideTimerRef.current = null; }
    if (fadeIntervalRef.current) { clearInterval(fadeIntervalRef.current); fadeIntervalRef.current = null; }
    setOpacity(1);
  }, []);

  // Reset the "viewed" flag when new tasks start processing
  useEffect(() => {
    if (processingCount > 0) {
      hasViewedAfterDone.current = false;
    }
  }, [processingCount]);

  // Only start auto-hide AFTER user has viewed and closed the panel
  useEffect(() => {
    if (allDone && !expanded && hasViewedAfterDone.current) {
      startAutoHide();
    } else {
      stopAutoHide();
    }
    return () => stopAutoHide();
  }, [allDone, expanded]);

  const handleExpandPanel = () => {
    setExpanded(true);
    stopAutoHide();
    if (allDone) {
      hasViewedAfterDone.current = true;
    }
  };

  const handleClose = () => {
    setExpanded(false);
    // Only start countdown after user has viewed the completed tasks
    if (allDone && hasViewedAfterDone.current) {
      startAutoHide();
    }
  };

  useEffect(() => {
    if (showGuideAnimation) {
      const timer = setTimeout(clearGuideAnimation, 3000);
      return () => clearTimeout(timer);
    }
  }, [showGuideAnimation, clearGuideAnimation]);

  const handleTaskClick = (task: BGVideoTask) => {
    if (task.recipeData) {
      setSelectedTask(task);
    }
  };

  if (!hasVisible && !selectedTask) return null;

  const getStatusIcon = (task: BGVideoTask) => {
    if (task.status === "creating" || task.status === "processing")
      return <Loader2 className="h-4 w-4 animate-spin text-primary" />;
    if (task.status === "succeeded")
      return <CheckCircle2 className="h-4 w-4 text-green-500" />;
    return <XCircle className="h-4 w-4 text-destructive" />;
  };

  const getStatusText = (task: BGVideoTask) => {
    if (task.status === "creating") return t("videoTask.creating", "提交中...");
    if (task.status === "processing") return t("videoTask.processing", "生成中...");
    if (task.status === "succeeded") return t("videoTask.succeeded", "已完成");
    return t("videoTask.failed", "失败");
  };

  return (
    <>
      <div
        className="fixed top-16 right-3 z-[60] transition-opacity duration-300"
        style={{ opacity }}
      >
        {showGuideAnimation && (
          <div className="absolute -left-20 top-2 flex items-center gap-1 animate-bounce text-primary">
            <span className="text-xs font-medium whitespace-nowrap">{t("videoTask.guideHint", "视频在这里 →")}</span>
          </div>
        )}

        {!expanded ? (
          <button
            onClick={handleExpandPanel}
            className={cn(
              "flex items-center gap-2 px-3 py-2 rounded-xl shadow-lg border backdrop-blur-md",
              "bg-background/95 hover:bg-background transition-all",
              showGuideAnimation && "ring-2 ring-primary ring-offset-2 animate-pulse"
            )}
          >
            {processingCount > 0 ? (
              <Loader2 className="h-4 w-4 animate-spin text-primary" />
            ) : (
              <Video className="h-4 w-4 text-primary" />
            )}
            <span className="text-xs font-medium">
              {processingCount > 0
                ? t("videoTask.generatingCount", "生成中 ({{count}})", { count: processingCount })
                : t("videoTask.completedCount", "已完成 ({{count}})", { count: completedUnviewed })}
            </span>
            <ChevronDown className="h-3 w-3 text-muted-foreground" />
          </button>
        ) : (
          <div className="w-72 rounded-xl shadow-xl border bg-background/95 backdrop-blur-md overflow-hidden">
            <div
              onClick={handleClose}
              className="flex items-center justify-between px-3 py-2 border-b cursor-pointer hover:bg-muted/50 transition-colors"
            >
              <div className="flex items-center gap-2">
                <Video className="h-4 w-4 text-primary" />
                <span className="text-sm font-medium">{t("videoTask.title", "视频生成")}</span>
              </div>
              <ChevronUp className="h-3.5 w-3.5 text-muted-foreground" />
            </div>
            <div className="max-h-60 overflow-y-auto">
              {visibleTasks.map(task => (
                <div
                  key={task.id}
                  className={cn(
                    "flex items-center gap-3 px-3 py-2.5 border-b last:border-b-0 hover:bg-muted/30",
                    task.recipeData && "cursor-pointer"
                  )}
                  onClick={() => handleTaskClick(task)}
                >
                  <div className="w-10 h-10 rounded-lg overflow-hidden bg-muted shrink-0 relative">
                    <img src={task.imageUrl} alt="" className="w-full h-full object-cover" />
                    {(task.status === "creating" || task.status === "processing") && (
                      <div className="absolute inset-0 bg-black/30 flex items-center justify-center">
                        <Loader2 className="h-3.5 w-3.5 animate-spin text-white" />
                      </div>
                    )}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-xs font-medium truncate">{task.recipeName}</p>
                    <div className="flex items-center gap-1.5 mt-0.5">
                      {getStatusIcon(task)}
                      <span className="text-[11px] text-muted-foreground">{getStatusText(task)}</span>
                    </div>
                    {task.recipeData && (
                      <p className="text-[10px] text-primary mt-0.5">
                        {t("videoTask.tapToViewRecipe", "点击查看食谱")}
                      </p>
                    )}
                  </div>
                  {(task.status === "succeeded" || task.status === "failed") && (
                    <button
                      onClick={(e) => { e.stopPropagation(); markViewed(task.id); }}
                      className="p-1 rounded hover:bg-muted shrink-0"
                    >
                      <X className="h-3.5 w-3.5 text-muted-foreground" />
                    </button>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Recipe detail dialog opened from widget */}
      {selectedTask?.recipeData && (
        <Suspense fallback={null}>
          <SavedRecipeDetailDialog
            open={!!selectedTask}
            onOpenChange={(o) => { if (!o) setSelectedTask(null); }}
            recipe={selectedTask.recipeData}
            recipeName={selectedTask.recipeName}
            initialImageUrl={selectedTask.imageUrl}
            enableVideoGeneration
          />
        </Suspense>
      )}
    </>
  );
};

export default VideoTaskFloatingWidget;
