/**
 * ⚠️ 优化警告 / OPTIMIZATION WARNING ⚠️
 * 
 * 此文件包含核心认证 Context，优化时请特别注意以下问题：
 * This file contains the core authentication Context. Be careful when optimizing:
 * 
 * 1. 循环依赖风险 / Circular Dependency Risk:
 *    - 不要在此文件中导入任何使用 useAuth() 的组件
 *    - Do NOT import any component that uses useAuth() in this file
 *    - 如果导入的组件内部使用了 useAuth，会导致 createContext undefined 错误
 *    - If imported component uses useAuth internally, it will cause createContext undefined error
 * 
 * 2. createContext 初始化顺序 / createContext Initialization Order:
 *    - AuthContext 必须在任何消费它的组件之前初始化
 *    - AuthContext must be initialized before any component that consumes it
 *    - 拆分文件时，确保 createContext 调用在最早加载的模块中
 *    - When splitting files, ensure createContext call is in the earliest loaded module
 * 
 * 3. 安全重构建议 / Safe Refactoring Suggestions:
 *    - 如需在 Provider 中渲染复杂组件，考虑使用 React.lazy() 延迟加载
 *    - If rendering complex components in Provider, consider using React.lazy()
 *    - 或将组件渲染移至 App.tsx 并通过 props/context 传递状态
 *    - Or move component rendering to App.tsx and pass state via props/context
 * 
 * 常见错误信息 / Common Error Message:
 * "Cannot read properties of undefined (reading 'createContext')"
 */
import { createContext, useContext, useEffect, useState, useRef, ReactNode, useCallback } from "react";
import { User, Session } from "@supabase/supabase-js";
import { registerFCMTokenIfAvailable } from "@/lib/fcmBridge";
import { supabase } from "@/integrations/supabase/client";
import { useNavigate } from "react-router-dom";

// ====== Rate-limit circuit breaker ======
// The PRIMARY fetch interceptor is in main.tsx (runs before SDK init).
// These helpers manage shared state used by that interceptor.
let rateLimitCircuitOpen = !!(typeof window !== 'undefined' && (window as any).__authCircuitOpen);
const AUTH_REFRESH_PAUSED_KEY = "auth_refresh_paused";

const setAuthRefreshPaused = (paused: boolean) => {
  try {
    if (paused) {
      localStorage.setItem(AUTH_REFRESH_PAUSED_KEY, "1");
      if (typeof window !== 'undefined') (window as any).__authCircuitOpen = true;
    } else {
      localStorage.removeItem(AUTH_REFRESH_PAUSED_KEY);
      if (typeof window !== 'undefined') (window as any).__authCircuitOpen = false;
    }
  } catch {
    // ignore storage errors
  }
};

const isAuthRefreshPaused = (): boolean => {
  try {
    return localStorage.getItem(AUTH_REFRESH_PAUSED_KEY) === "1";
  } catch {
    return false;
  }
};

const clearStoredAuthTokens = () => {
  if (typeof window === "undefined") return;
  try {
    const localKeysToRemove: string[] = [];
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && (key.includes("-auth-token") || key.startsWith("sb-"))) {
        localKeysToRemove.push(key);
      }
    }
    localKeysToRemove.forEach((k) => localStorage.removeItem(k));
    const sessionKeysToRemove: string[] = [];
    for (let i = 0; i < sessionStorage.length; i++) {
      const key = sessionStorage.key(i);
      if (key && (key.includes("-auth-token") || key.startsWith("sb-") || key === "authSessionActive")) {
        sessionKeysToRemove.push(key);
      }
    }
    sessionKeysToRemove.forEach((k) => sessionStorage.removeItem(k));
  } catch {
    // ignore storage access failures
  }
};

const stopAuthAutoRefresh = () => {
  try { supabase.auth.stopAutoRefresh(); } catch { /* ignore */ }
};

const startAuthAutoRefresh = () => {
  try { supabase.auth.startAutoRefresh(); } catch { /* ignore */ }
};

const applyAuthPauseLocally = async (clearTokens: boolean = true) => {
  stopAuthAutoRefresh();
  if (clearTokens) {
    clearStoredAuthTokens();
  }
  await supabase.auth.signOut({ scope: "local" }).catch(() => {});
};

// On module load:
// - If paused from a previous storm, keep circuit breaker active
// - If on /auth page, clean local auth state WITHOUT pausing password login
if (typeof window !== 'undefined') {
  const onAuthPage = window.location.pathname.startsWith('/auth');
  const paused = isAuthRefreshPaused();

  if (paused) {
    setAuthRefreshPaused(true);
    rateLimitCircuitOpen = true;
    void applyAuthPauseLocally(true);
  } else if (onAuthPage) {
    rateLimitCircuitOpen = false;
    setAuthRefreshPaused(false);
    clearStoredAuthTokens();
    stopAuthAutoRefresh();
    void supabase.auth.signOut({ scope: "local" }).catch(() => {});
  }
}
/**
 * ⚠️ 依赖约束 / DEPENDENCY CONSTRAINT ⚠️
 * BannedUserDialog 组件不能使用 useAuth() hook！
 * BannedUserDialog component MUST NOT use useAuth() hook!
 * 否则会导致循环依赖和 createContext undefined 错误
 * Otherwise it will cause circular dependency and createContext undefined error
 */
import BannedUserDialog from "@/components/BannedUserDialog";

interface AuthContextType {
  user: User | null;
  session: Session | null;
  signUp: (email: string, password: string, displayName: string, phone?: string) => Promise<{ data?: any; error: any }>;
  signIn: (email: string, password: string, rememberMe?: boolean) => Promise<{ error: any }>;
  signInWithGoogle: () => Promise<{ error: any }>;
  signInWithPhone: (phone: string) => Promise<{ error: any }>;
  verifyOTP: (phone: string, token: string) => Promise<{ error: any }>;
  signOut: () => Promise<void>;
  loading: boolean;
  isBanned: boolean;
  isCheckingBanStatus: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

// 一个月的毫秒数
const ONE_MONTH_MS = 30 * 24 * 60 * 60 * 1000;

// Safe storage helpers for WebView compatibility
const safeGetItem = (storage: Storage, key: string): string | null => {
  try {
    return storage.getItem(key);
  } catch (e) {
    console.warn(`Storage access failed for key ${key}:`, e);
    return null;
  }
};

const safeSetItem = (storage: Storage, key: string, value: string): void => {
  try {
    storage.setItem(key, value);
  } catch (e) {
    console.warn(`Storage set failed for key ${key}:`, e);
  }
};

const safeRemoveItem = (storage: Storage, key: string): void => {
  try {
    storage.removeItem(key);
  } catch (e) {
    console.warn(`Storage remove failed for key ${key}:`, e);
  }
};

// Check if user is banned
const checkUserBanned = async (userId: string): Promise<{ isBanned: boolean; banReason?: string }> => {
  try {
    const { data, error } = await supabase
      .from("profiles")
      .select("is_banned, ban_reason")
      .eq("id", userId)
      .single();
    
    if (error) {
      console.warn("Failed to check ban status:", error);
      return { isBanned: false };
    }
    
    return { 
      isBanned: data?.is_banned === true,
      banReason: data?.ban_reason || undefined
    };
  } catch (e) {
    console.warn("Error checking ban status:", e);
    return { isBanned: false };
  }
};

export const AuthProvider = ({ children }: { children: ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);
  const [isBanned, setIsBanned] = useState(false);
  const [isCheckingBanStatus, setIsCheckingBanStatus] = useState(false);
  const [showBannedDialog, setShowBannedDialog] = useState(false);
  const [banReasonState, setBanReasonState] = useState<string | undefined>();
  // Ref to skip duplicate ban check from onAuthStateChange when signIn is handling it
  const signInBanCheckActiveRef = useRef(false);
  // Grace period ref to prevent transient SIGNED_OUT from clearing state after login
  const recentLoginRef = useRef(false);
  const sessionRef = useRef<Session | null>(null);
  const navigate = useNavigate();

  // Execute the actual sign out for banned user
  const executeSignOut = useCallback(async () => {
    // Clear sessionRef FIRST so onAuthStateChange knows this is a real sign-out
    sessionRef.current = null;
    recentLoginRef.current = false;
    
    // Clear local state
    setUser(null);
    setSession(null);
    setIsBanned(false);
    setShowBannedDialog(false);
    setBanReasonState(undefined);
    
    // Clear all storage
    safeRemoveItem(localStorage, "sb-tzdgqhwyzsxkxnncgzap-auth-token");
    safeRemoveItem(localStorage, "rememberMe");
    safeRemoveItem(localStorage, "rememberMeExpireAt");
    safeRemoveItem(sessionStorage, "authSessionActive");
    
    // Sign out from Supabase
    try {
      await supabase.auth.signOut();
    } catch (e) {
      console.warn("Sign out during ban check failed:", e);
    }
    
    // Navigate to auth page
    navigate("/auth");
  }, [navigate]);


  // Handle user confirming they understand they are banned
  const handleBannedDialogConfirm = useCallback(async () => {
    await executeSignOut();
  }, [executeSignOut]);

  // Check if merchant joined and notify admins via edge function
  const checkMerchantJoinAndNotify = async (userEmail: string) => {
    try {
      const loginTime = new Date().toISOString();
      const { data, error } = await supabase.functions.invoke("check-merchant-login", {
        body: { email: userEmail, loginTime },
      });

      if (error) {
        console.error("Error calling check-merchant-login:", error);
        return;
      }

      if (data?.success && data?.restaurantName) {
        console.log("Merchant join completed and admins notified:", data.restaurantName);
      }
    } catch (error) {
      console.error("Error in checkMerchantJoinAndNotify:", error);
    }
  };

  useEffect(() => {
    let mounted = true;
    // Background ban check helper (does NOT affect loading state)
    const runBanCheck = (userId: string, userEmail?: string | null) => {
      setIsCheckingBanStatus(true);
      setTimeout(() => {
        if (!mounted) return;
        checkUserBanned(userId).then(({ isBanned: userIsBanned, banReason }) => {
          if (!mounted) return;
          if (userIsBanned) {
            setIsBanned(true);
            setBanReasonState(banReason);
            setShowBannedDialog(true);
          } else if (userEmail) {
            checkMerchantJoinAndNotify(userEmail);
            registerFCMTokenIfAvailable().catch(e => console.warn("[FCM] Registration failed:", e));
          }
          setIsCheckingBanStatus(false);
        }).catch(() => {
          if (mounted) setIsCheckingBanStatus(false);
        });
      }, 0);
    };

    // 用于防止初始化时 onAuthStateChange 重复触发 ban check
    let initialSessionProcessed = false;

    // 检查 rememberMe 过期（仅检查明确设置了 rememberMe 且已过期的情况）
    const checkRememberMeExpiry = (): boolean => {
      try {
        const rememberMe = safeGetItem(localStorage, "rememberMe") === "true";
        const expireAt = safeGetItem(localStorage, "rememberMeExpireAt");

        if (rememberMe && expireAt) {
          const expireTime = parseInt(expireAt, 10);
          if (Date.now() > expireTime) {
            // 已超过一个月，清除 session
            safeRemoveItem(localStorage, "sb-tzdgqhwyzsxkxnncgzap-auth-token");
            safeRemoveItem(localStorage, "rememberMeExpireAt");
            safeRemoveItem(localStorage, "rememberMe");
            return false; // 已过期
          }
        }
        return true;
      } catch (e) {
        console.warn("Session validity check failed:", e);
        return true;
      }
    };

    // 1. 先设置 onAuthStateChange 监听（监听后续变化，不控制 loading）
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      (event, currentSession) => {
        if (!mounted) return;

        console.log(`[Auth] onAuthStateChange: event=${event}, hasSession=${!!currentSession}, userId=${currentSession?.user?.id?.slice(0, 8) || 'none'}, recentLogin=${recentLoginRef.current}, hasSessionRef=${!!sessionRef.current}`);

        // If SDK reports null session while we still have one in memory, only ignore
        // it during a short post-login grace period; never re-persist old tokens.
        if (!currentSession && sessionRef.current) {
          if (recentLoginRef.current && event !== 'SIGNED_OUT') {
            console.warn("[Auth] Ignoring transient null session during login grace period (event:", event, ")");
            return;
          }
        }
        if (!currentSession && !sessionRef.current) {
          // No existing session, this is a legitimate unauthenticated state
        }

        // Guard against session from a different user overwriting current session
        // (can happen in multi-tab scenarios during token refresh storms)
        if (currentSession && sessionRef.current && 
            currentSession.user?.id !== sessionRef.current.user?.id &&
            recentLoginRef.current) {
          console.warn("[Auth] Ignoring session from different user during grace period:", 
            currentSession.user?.id?.slice(0, 8), "vs current:", sessionRef.current.user?.id?.slice(0, 8));
          return;
        }

        setSession(currentSession);
        setUser(currentSession?.user ?? null);
        if (currentSession) {
          sessionRef.current = currentSession;
        }

        if (event === 'SIGNED_IN' && currentSession) {
          const rememberMe = safeGetItem(localStorage, "rememberMe") === "true";
          if (rememberMe) {
            const expireAt = Date.now() + ONE_MONTH_MS;
            safeSetItem(localStorage, "rememberMeExpireAt", expireAt.toString());
          }
          safeSetItem(sessionStorage, "authSessionActive", "true");

          // 只有在初始化已完成后且不在 signIn 流程中，才通过事件触发 ban check
          if (currentSession.user?.id && initialSessionProcessed && !signInBanCheckActiveRef.current) {
            runBanCheck(currentSession.user.id, currentSession.user.email);
          }
        }

        if (event === 'SIGNED_OUT') {
          sessionRef.current = null;
          safeRemoveItem(localStorage, "rememberMeExpireAt");
          safeRemoveItem(sessionStorage, "authSessionActive");
          // 立即清除所有 auth token，防止 SDK 使用已失效的 refresh_token 重试
          clearStoredAuthTokens();
        }

        if (event === 'TOKEN_REFRESHED' && currentSession) {
          safeSetItem(sessionStorage, "authSessionActive", "true");
        }
      }
    );

    // 2. 初始化：获取当前 session，完成后才设置 loading = false
    const initializeAuth = async () => {
      try {
        // If storm was detected before, skip bootstrap session refresh to avoid loop
        if (isAuthRefreshPaused()) {
          if (mounted) {
            setUser(null);
            setSession(null);
          }
          return;
        }

        const isValid = checkRememberMeExpiry();
        if (!isValid) {
          // 过期了，强制登出
          await supabase.auth.signOut().catch(() => {});
          if (mounted) {
            setUser(null);
            setSession(null);
          }
          return;
        }

        const { data: { session } } = await supabase.auth.getSession();
        if (!mounted) return;

        setSession(session);
        setUser(session?.user ?? null);
        if (session) sessionRef.current = session;

        if (session?.user) {
          safeSetItem(sessionStorage, "authSessionActive", "true");
          // ban check 在后台运行，不阻塞 loading
          setTimeout(() => {
            if (!mounted) return;
            checkUserBanned(session.user.id).then(({ isBanned: userIsBanned, banReason }) => {
              if (!mounted) return;
              if (userIsBanned) {
                setIsBanned(true);
                setBanReasonState(banReason);
                setShowBannedDialog(true);
              } else if (session.user?.email) {
                checkMerchantJoinAndNotify(session.user.email);
              }
            }).catch(() => {});
          }, 0);
        }
      } catch (e) {
        console.warn("Auth initialization failed:", e);
      } finally {
        // 无论如何，初始化完成后才解除 loading，并标记初始化完成
        if (mounted) {
          initialSessionProcessed = true;
          setLoading(false);
        }
      }
    };

    initializeAuth();

    // Listen for storage events to pick up token refreshed by another tab
    const handleStorageChange = (e: StorageEvent) => {
      if (!mounted) return;

      if (e.key === AUTH_REFRESH_PAUSED_KEY && e.newValue === "1") {
        setSession(null);
        setUser(null);
        sessionRef.current = null;
        void applyAuthPauseLocally(true);
        return;
      }

      if (isAuthRefreshPaused()) return;

      if (e.key === 'sb-tzdgqhwyzsxkxnncgzap-auth-token' && e.newValue) {
        // Another tab refreshed the token, get the updated session
        supabase.auth.getSession().then(({ data: { session: newSession } }) => {
          if (mounted && newSession) {
            setSession(newSession);
            setUser(newSession.user);
            sessionRef.current = newSession;
          }
        });
      }
    };
    window.addEventListener('storage', handleStorageChange);

    return () => {
      mounted = false;
      subscription.unsubscribe();
      window.removeEventListener('storage', handleStorageChange);
    };
  }, [navigate]);

  const signUp = async (email: string, password: string, displayName: string, phone?: string) => {
    const redirectUrl = `${window.location.origin}/`;
    const normalizedEmail = email.trim().toLowerCase();
    
    const { data, error } = await supabase.auth.signUp({
      email: normalizedEmail,
      password,
      options: {
        emailRedirectTo: redirectUrl,
        data: {
          display_name: displayName,
          phone: phone || null,
        },
      },
    });
    
    return { data, error };
  };

  const signIn = async (email: string, password: string, rememberMe: boolean = false) => {
    const normalizedEmail = email.trim().toLowerCase();
    // 保存 rememberMe 状态
    safeSetItem(localStorage, "rememberMe", rememberMe.toString());
    
    if (rememberMe) {
      // 设置过期时间为一个月后
      const expireAt = Date.now() + ONE_MONTH_MS;
      safeSetItem(localStorage, "rememberMeExpireAt", expireAt.toString());
    } else {
      safeRemoveItem(localStorage, "rememberMeExpireAt");
    }

    const isAuthRateLimitError = (err: any) => {
      const message = String(err?.message || "").toLowerCase();
      const code = String(err?.code || "").toLowerCase();
      return (
        code === "over_request_rate_limit" ||
        message.includes("rate limit") ||
        message.includes("over_request_rate_limit")
      );
    };

    const clearLocalAuthState = async () => {
      stopAuthAutoRefresh();
      // Do NOT set paused=true here — we're about to retry login
      // and setting it would re-block the fetch interceptor
      setAuthRefreshPaused(false);

      clearStoredAuthTokens();
      sessionRef.current = null;
      setSession(null);
      setUser(null);

      // Local signout only, avoid extra network pressure
      try { await supabase.auth.signOut({ scope: "local" }); } catch {}
    };
    
    // Mark that signIn is handling ban check, prevent duplicate from onAuthStateChange
    signInBanCheckActiveRef.current = true;
    // Set login grace period to ignore transient SIGNED_OUT from token refresh storms
    recentLoginRef.current = true;
    setTimeout(() => { recentLoginRef.current = false; }, 30000); // Extended to 30s for slower connections
    setIsCheckingBanStatus(true);

    // Ensure background refresh won't race with password login
    stopAuthAutoRefresh();
    rateLimitCircuitOpen = false;
    // CRITICAL: Clear ALL circuit breaker flags BEFORE attempting login
    // so the fetch interceptor and SDK don't interfere with the password request
    setAuthRefreshPaused(false);
    clearStoredAuthTokens();
    try {
      localStorage.removeItem("auth_circuit_breaker_ts");
      if (typeof window !== 'undefined') (window as any).__passwordLoginInProgress = true;
    } catch {}
    
    let { data, error } = await supabase.auth.signInWithPassword({
      email: normalizedEmail,
      password,
    });

    // Self-heal: if rate limited, hard-reset and retry with increasing delays
    if (error && isAuthRateLimitError(error)) {
      console.warn("[Auth] Password login hit rate limit, applying local auth reset and retrying");
      await clearLocalAuthState();
      
      // Try up to 2 more times with increasing delays
      for (const delay of [6000, 12000]) {
        await new Promise((resolve) => setTimeout(resolve, delay));
        // Clear flags again before retry
        setAuthRefreshPaused(false);
        try { localStorage.removeItem("auth_circuit_breaker_ts"); } catch {}
        
        const retryResult = await supabase.auth.signInWithPassword({
          email: normalizedEmail,
          password,
        });
        data = retryResult.data;
        error = retryResult.error;
        if (!error || !isAuthRateLimitError(error)) break;
      }
    }
    
    if (!error && data?.session && data?.user) {
      // Login succeeded: resume auto refresh and clear pause flag
      setAuthRefreshPaused(false);
      startAuthAutoRefresh();
      rateLimitCircuitOpen = false;

      // Immediately set session and user state from signIn response
      // This prevents relying solely on onAuthStateChange which can be disrupted by token refresh storms
      setSession(data.session);
      setUser(data.user);
      sessionRef.current = data.session;
      
      // Check if user is banned
      const { isBanned: userIsBanned, banReason } = await checkUserBanned(data.user.id);
      if (userIsBanned) {
        setIsBanned(true);
        setBanReasonState(banReason);
        setShowBannedDialog(true);
        signInBanCheckActiveRef.current = false;
        return { 
          error: { 
            message: "ACCOUNT_BANNED"
          } 
        };
      }
      
      // 设置当前会话标记
      safeSetItem(sessionStorage, "authSessionActive", "true");
      
      // Register FCM and check merchant in background
      if (data.user.email) {
        checkMerchantJoinAndNotify(data.user.email);
      }
      registerFCMTokenIfAvailable().catch(e => console.warn("[FCM] Registration failed:", e));
    }
    
    // Reset checking status and signIn flag
    setIsCheckingBanStatus(false);
    signInBanCheckActiveRef.current = false;
    try { if (typeof window !== 'undefined') (window as any).__passwordLoginInProgress = false; } catch {}
    
    return { error };
  };

  const signInWithGoogle = async () => {
    const { error } = await supabase.auth.signInWithOAuth({
      provider: "google",
      options: {
        redirectTo: `${window.location.origin}/`,
      },
    });
    
    return { error };
  };

  const signInWithPhone = async (phone: string) => {
    const { error } = await supabase.auth.signInWithOtp({
      phone,
      options: {
        channel: 'sms',
      },
    });
    
    return { error };
  };

  const verifyOTP = async (phone: string, token: string) => {
    const { error } = await supabase.auth.verifyOtp({
      phone,
      token,
      type: 'sms',
    });
    
    return { error };
  };

  const signOut = async () => {
    // Clear sessionRef FIRST so onAuthStateChange knows this is a real sign-out
    sessionRef.current = null;
    recentLoginRef.current = false;
    
    // Clear local state to ensure UI updates immediately
    setUser(null);
    setSession(null);
    
    // Clear auth token and remember me from localStorage (using safe helpers for WebView)
    safeRemoveItem(localStorage, "sb-tzdgqhwyzsxkxnncgzap-auth-token");
    safeRemoveItem(localStorage, "rememberMe");
    safeRemoveItem(localStorage, "rememberMeExpireAt");
    safeRemoveItem(sessionStorage, "authSessionActive");
    
    // Try to sign out from Supabase (ignore errors if session already expired)
    try {
      const { error } = await supabase.auth.signOut();
      if (error) {
        console.log("Sign out completed (session may have already expired):", error.message);
      }
    } catch (e) {
      console.warn("Sign out failed:", e);
    }
    
    navigate("/auth");
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        session,
        signUp,
        signIn,
        signInWithGoogle,
        signInWithPhone,
        verifyOTP,
        signOut,
        loading,
        isBanned,
        isCheckingBanStatus,
      }}
    >
      {children}
      <BannedUserDialog
        open={showBannedDialog}
        banReason={banReasonState}
        onConfirm={handleBannedDialogConfirm}
      />
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};