/**
 * Wrapper around React.lazy() that automatically retries on chunk load failure.
 * 
 * When a new version is deployed, old JS chunks are replaced with new filenames.
 * Users with cached HTML may try to load stale chunks that no longer exist,
 * causing "Failed to fetch dynamically imported module" errors.
 * 
 * This wrapper detects such failures and reloads the page once to fetch
 * the latest HTML entry point with correct chunk references.
 */
import { lazy, ComponentType } from 'react';

const RELOAD_KEY = 'chunk-reload-attempted';

export function lazyRetry<T extends ComponentType<any>>(
  factory: () => Promise<{ default: T }>
) {
  return lazy(() =>
    factory().catch((error) => {
      // Check if we've already tried reloading to prevent infinite loops
      const hasReloaded = sessionStorage.getItem(RELOAD_KEY);

      if (!hasReloaded) {
        sessionStorage.setItem(RELOAD_KEY, 'true');
        console.warn('[lazyRetry] Chunk load failed, reloading page:', error);
        window.location.reload();
        // Return a never-resolving promise to prevent rendering while reloading
        return new Promise<{ default: T }>(() => {});
      }

      // Already reloaded once, clear flag and let error propagate
      sessionStorage.removeItem(RELOAD_KEY);
      throw error;
    })
  );
}

// Clear the reload flag on successful app load
if (typeof window !== 'undefined') {
  window.addEventListener('load', () => {
    sessionStorage.removeItem(RELOAD_KEY);
  });
}
